class WorkflowsPage extends StatelessWidget { const WorkflowsPage({super.key}); static const workflows=[('Matrícula e rematrícula','Processo, documentos, contrato, vaga e cobrança inicial'),('Financeiro','Planos, parcelas, boletos, pagamentos, baixas e inadimplência'),('Frequência','Chamada por aula, frequência por aluno e justificativas'),('Avaliações','Instrumentos, notas, fórmula, boletim e histórico'),('Comunicação','Comunicados, conversas, leitura e preferências'),('LGPD','Consentimentos, inventário, exportação e solicitação de titular'),('Implantação','Importação, validação, erros e tarefas de onboarding'),('IA assistiva','Alertas explicáveis, revisáveis e não decisórios')]; @override Widget build(BuildContext context)=>ResponsiveScaffold(title:'Fluxos operacionais', child:ListView(padding:const EdgeInsets.all(24), children:[Text('Workflows implementados no backend', style:Theme.of(context).textTheme.headlineSmall), const SizedBox(height:8), const Text('Operações críticas usam backend, tenant context, RBAC, auditoria e RLS.'), const SizedBox(height:24), for(final w in workflows) Card(child:ListTile(leading:const Icon(Icons.route_outlined), title:Text(w.$1), subtitle:Text(w.$2), trailing:const Icon(Icons.check_circle_outline)))]));}
